const Q_GEOGRAPHY_2007=[{"id": "objective>Geography>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The area likely to experience seasonal flooding lies</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">above a 120 metre contour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">between 105 and 120-metre contours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">between 105 and 135-metre contours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">below a 105-metre contour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> From the map, areas below 105m are liable to flooding as river floods flow from the surrounding highlands down to the depression.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Kondo is situated mainly on a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gap</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kondo settlement is located on a gap. A gap is a space between two peaks of a hill/mountain. Even though it is in itself a highland and usually exploited for transportation and communication purposes.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The slope east of Park-Gbo Road is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gentle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concave</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steep</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The slope is steep as the vertical height arises sharply and contour lines are closely packed together.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Abag and Lobodo are most likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">educational settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial settlements</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mining settlements based on the number of mining sites surrounding these settlements.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total length of the railway line is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.5km</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Measure length of river traced with white thread on metre rule = 11.5cm  <br/>  but scale = 1cm = 1km  <br/>  = 11.5km</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><em><strong>Use the diagram below to answer this question</strong></em> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The textural class that can hold the greatest amount of moisture is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sand loam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay loam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ability to hold the greatest amount of moisture = field capacity  <br/>  Clay has the highest field capacity of  <br/>  ≈ 325mm from the graph.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <em><strong>Use the diagram below to answer this question</strong></em> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The amount of moisture retained by clay loam soil is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100mm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">With greatest available moisture from the graph of over 150mm</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ranging poles are important in chain and prismatic compass surveys to determine</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the total length of all offsets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the length of all offsets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the length of the base line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three points along a straight line.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ranging poles help in setting observation points from which bearings and distances are calculated based on triangulation & in chain and prismatic compass surveys.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A slope is said to be even when the contours are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equally spaced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closely spaced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">irregularly spaced</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equally spaced slopes can be referred to as being even, i.e resulting in a flat or table-like formation/feature.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chemical weathering in tropical Africa creates domed rock outcroppings called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volcanic rocks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">escarpments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inselbergs</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chemical weathering in tropical Africa often results in the formation of inselbergs. Inselbergs are isolated hill, knob, ridge, outcrop, or small mountain that rises abruptly from a gently sloping or virtually level surrounding plain. They are caused by the deep weathering of the bedrock, leaving the more resistant rock standing out in the landscape.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><em><strong>Use the map below to answer this question</strong></em> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the following ethnic groups is mainly found in the area marked <strong>I</strong>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Ijaw</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Kanuri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Tiv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Tivs are found mainly in Benue state and surrounding regions of Middle-Belt Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <em><strong>Use the map below to answer this question</strong></em> <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The major export crop cultivated in the area marked <strong>III</strong> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">groundnut </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sugarcane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The world renowned groundnut pyramids are associated with the North/West Geopolitical region of Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : FRUIT FARMING IN THE MEDITERRANEAN REGIONS OF AFRICA."}, {"id": "objective>Geography>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest volcanic regions of Africa are found in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sudan and Ethiopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Maghrib</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kenya and Tanzania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Camerouns</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kenya and Tanzania cover most areas of the East-African Rift Valley System. With associated tectonic movements and volcanic activities.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The south west of Nigeria is a major destination for internal migrants because the area is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">highly urbanized and has many industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">very close to the coast and has many industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">well endowed with petroleum resources and free from political crises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agriculturally rich and has a good climate </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South-Western Nigeria is highly urbanized with many industries these are strong pull factors of internal migration in Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The narrow neck of water separating Africa from Europe in the northwest is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cape of Good Hope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Suez Canal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Strait of Gigraltar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canary Islands</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The strait of Gibraltar is along the Mediterranean in North-West Africa separating Africa from Europe.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest peak in Nigeria can be found on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oban Hills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Uplands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa Highlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest peak in Nigeria can be found in the Adamawa Highlands on the borders of Cameroon on the Cameroon mountains regions.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The exploitation of timber in equatorial Africa causes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soil erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environment pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less rainfall run-off</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high cost of forest products</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The exploitation of timber in equatorial Africa leads to deforestation which in turn causes soil erosion. Therefore, the correct answer is 'soil erosion'.</div>", "topic": "PRATICAL GEOGRAPHY II : LUMBERING IN EQUATORIAL AFRICA"}, {"id": "objective>Geography>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the areas noted for paddy rice production in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Enugu Scarpland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obudu Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Badeggi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mixed farming</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Badeggi in Niger state located within the catchment of the River Niger waterled is noted for Paddy rice production in Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of extensive farming system in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pastoral farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market gardening</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed farming</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mixed farming is the most demanding option among answers offered. It involves cultivating different kinds of crops & animals arranged within the same farmland area.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major gold mining centre in South Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kimberley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kuruman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Newcastle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Klerkdrop</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Kimberley is the capital of the Northern Cape province of South Africa, notable for its massive gold mining industry.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ocean current that affects the climate of the Atlantic coast from South Africa to Southern Angola is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mozanbique</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benguela</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Equatorial</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Benguela cold current is responsible for the Namib Desert and Climate conditions of coastal (Atlantic) South Africa and Southern Angola.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country that is connected to Nigeria's electricity grid is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cote d'Ivoire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger Republic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ghana is connected to Nigeria's electricity grid as part of the West Africa Power Project.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highlands of East Africa attract settlers because of their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">agricultural potentials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">good transportation network</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educational potentials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tourist potentials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highlands of East Africa are popular tormits sites for safaris, volcano landform viewing etc.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soil type that is predominant in the Niger Benue trough is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sandy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clayey</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alluvial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loamy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alluvial deposits are predominant along the Niger-Benue trough. Due to deposition by these great rivers.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure marked <strong>Y</strong> is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">batholith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lopolith</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Batholiths are results of cooled magma (Plutonic rocks) deep within the earth's crust. Usually very large in size.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure marked <strong>X</strong> is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ridge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">laccolith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lopolith</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dykes are large vertical rocks between older layers of rock. Usually igneous in origin cutting through flat structures like beddings.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of argillaceous rock is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chalk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argillaceous rocks are usually sedimentary rocks with silt or clay sized particles less than 0.0625mm and/or clay minerals forming a significant component e.g shale, siltstones, argillites and mudstones.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the broadest sense, the two major types of ecosystems are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">terrestrial and arboreal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aquatic and vegetal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">terrestrial and aquatic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aquatic and aboreal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the broadest sense, the two major types of ecosystems are terrestrial and aquatic. Terrestrial ecosystems are land-based, while aquatic ecosystems are water-based. The other options do not correctly categorize the major types of ecosystems.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rock type whose principal constituents can be seen without magnification is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basalt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandstone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sandstone is a type of rock whose principal constituents can be seen without magnification. It is a clastic sedimentary rock composed mainly of sand-sized mineral particles or rock fragments. The other options are not typically visible without magnification.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Adoline is associated with a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marine platform</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite upland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">karst valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rocky desert</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Karst valley of limestone regions occur as depressions along lines of least resistant leading to a sink hole or doline.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two potent human factors that destabilize ecosystems are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">afforestation and logging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocropping and reforestation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reforestation and mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocropping and mining</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monocropping interfers with the normal proces of ecological succession making the flora more susceptible to that particular species pests and diseases. Mining also totally disrupts and destroys the hydrosphere, lithosphere and atmosphere changing adaptability of species to newly created degraded environment.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The weight of water vapour contained in a given volume of air is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absolute humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specific humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vapour pressure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Relative humidity measures the volume of water in a given volume of air. A critical factor for condensation and cloud formation.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of evidence that confirms that the earth is spherical is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">standard time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solar system </div>", "<div style=\"font-family:Cambria;font-size:17px;\">earth's orbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moon's eclipse</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During a lunar eclipse the Earth casts its shadow on the moon. The form displayed is spherical in shape in the event of a lunar eclipse.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil texture is determined primarily by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profile horizons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">major components</div>", "<div style=\"font-family:Cambria;font-size:17px;\">particle sizes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrient status</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Particle sizes determine the texture of a soil. Smaller sizes are finer e.g clay while larger sizes are coarse e.g sand.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two primary causes of ocean currents are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">differential algae development and sunlight penetration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variation in evaporation and coral development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">location of settlements and sea-level pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid fluctuation of temperature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Differentials in salinity between fresh and salt water bodies (inland rivers versus oceans) as well as temperature variation between land and sea influence the cycles of ocean currents globally.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil conservation is achieved through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mulching, terrace farming and tree-felling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sensible tillage, tree-felling and bush burning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scientific farming, crop rotation and bush burning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sensible tillage, crop rotation and mulching</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sensible tillage, crop rotation and mulching (Use of natural/artificial materials to cover exposed earth surface) are all adept methods to soil conservation dining crop cultivation.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Sudan savanna vegetation is associated with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical monsoon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sub-tropical dry summer climate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hot semi-desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical dry and wet climate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hot semi-desert conditions are responsible for sudan savannah vegetations as found in borno North/East Nigeria.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A weather element controlled mainly by latitude is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cloud cover</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As one moves to the poles, direct solar radiation reduces, leading to cooler temperatures being observed.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is of great importance to plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Metal scraps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Industrial effluent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon(II)oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants require Carbon (IV) oxide for photosynthesis. Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. During this process, plants absorb carbon dioxide (CO2) from the atmosphere and release oxygen.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristics of an urban settlement is that it is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Industrialized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Limited in function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Homogeneous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heterogeneous</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Urban settlements are heterogenous i.e different cultures and tribal/ethnic/racial origins make up their populations.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is likely to be found in an oasis in the Sahara Desert?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Raffia palm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil palm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Date palm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Durn palm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Sahara Desert, an oasis is likely to have Date palms. Date palms are well adapted to the harsh desert conditions and are a common sight in desert oases. They provide a valuable source of food (dates) and other materials for the local inhabitants.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Birth and Death rates are often stated as the number of cases per</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1000 per year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 000 000 per year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 per year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 per year</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Birth and death rates are often stated as observed number of cases per 1000 people/population per year.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Weber's theory of industrial location was based on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nearness to market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nearness to raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nearness to source of power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">least transport cost</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alfred Weber's theory of industrial location propounds that an industry is located where the transportation costs of raw materials and final product is at minimum.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A poor settlement on the edge of a city is known as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shanty town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ghetto</div>", "<div style=\"font-family:Cambria;font-size:17px;\">new town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slum</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Slums occur on the urban fringes filled with fresh migrants and low income workers with little or no/denlict social infrastructures available there with cheap access to usually illegal/inhabitable land.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A desert country which has a high population density supported by irrigation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kuwait</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Namibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Egypt</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Egypt though in the Desert has fully exploited and managed water from the Nile through dams for irrigation, domestic and industrial purposes.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The speed and capacity of a train are influenced by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">length of the railway line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the edge of the railway line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">width of the railway gauge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depth of the railway line</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The width of the railway gauge determines if its is narrow or standard gauge with resultant effect on.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of a country in 1990 and 2005 is given as 46,850,112 and 58,855,827 respectively. The approximate annual population increase is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">650 381</div>", "<div style=\"font-family:Cambria;font-size:17px;\">700 381</div>", "<div style=\"font-family:Cambria;font-size:17px;\">750 381</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800 381</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Population increase</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">change in population<hr size=\"1\" />change in years</td></tr></table></div>  <br/>   <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Per annum increase</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Population increase<hr size=\"1\" />year</td></tr></table></div>  <br/>  1990 = 46,850,112  <br/>  2005 = 58,855,827.  <br/>  Change in population = 58855827 - 46850112  <br/>  = 12005715  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">PI</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12 005 715<hr size=\"1\" />15</td></tr></table></div>  <br/>  = 800381  <br/> ∴ PAI = 800,381 per year</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets of settlements is influenced by the presence of a water body?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lagos, Lokoja and Baga</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warri, Lagos and Yola</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kano, Port Harcourt and Enugu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benin, Sokoto and Calabar</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lokoja in kogi → River Niger confluence  <br/>  Lagos by the Atlantic ocean  <br/>  and Baga in Borno by late Chad have all had their settlements' growth influenced by being located by water bodies. </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors may lead to an area being densely populated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High plateaux</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lowland plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rugged mountains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Active volcanoes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lowland plains as opposed to active volcanoes, high plateau and rugged mountains encourage the growth of densely populated settlements. Usually good for flood plain farming because of good soil fertility and good real estates values of lands overseeing waterbodies.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The categorization of manufacturing industries as traditional crafts and factory industry is based on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the nature of the final product </div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour intensity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the form of technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital intensity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The technology involved influences the classification of manufacturing industries as traditional crafts & factory industries . Local small scale hand-made fabrications fall within this group.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}];
